parameters.url:
=https://export.arxiv.org/api/query?search_query={{ 
  $json.search_query.map(phrase => {
    // Split the phrase into individual words and prefix each with 'all:'
    // Example: "diffusion models audio" becomes (all:diffusion+AND+all:models+AND+all:audio)
    const terms = phrase.split(' ').map(word => 'all:' + encodeURIComponent(word.replace(/-/g, ' ')));
    return '(' + terms.join('+AND+') + ')';
  }).join('+OR+') 
}}&sortBy=submittedDate&sortOrder=descending&max_results={{ $json.max_papers || 15 }}

