const raw = $json.output;

// Remove markdown fences
const cleaned = raw
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

return [
  {
    json: JSON.parse(cleaned)
  }
];

// Input: $json.raw.data
const xml = $json.raw.data;

// Helper to extract single tag text
function extractTag(tag, text) {
  const match = text.match(new RegExp(`<${tag}[^>]*>([\\s\\S]*?)</${tag}>`, 'i'));
  return match ? match[1].trim() : null;
}

// Helper to extract multiple tags
function extractAllTags(tag, text) {
  const regex = new RegExp(`<${tag}[^>]*>([\\s\\S]*?)</${tag}>`, 'gi');
  let matches = [];
  let m;
  while ((m = regex.exec(text)) !== null) {
    matches.push(m[1].trim());
  }
  return matches;
}

// Split entries
const entryBlocks = xml.split('<entry>').slice(1);

// Get original user prompt safely
const originalPrompt =
  $node["Check research q"]?.json?.["initial user question"] ?? null;

// Build papers as n8n items
const papers = entryBlocks.map(entryXml => {
  // Authors
  const authorBlocks = entryXml.split('<author>').slice(1);
  const authors = authorBlocks.map(a => extractTag('name', a)).filter(Boolean);

  // Links
  const linkTags = entryXml.match(/<link[^>]+\/>/gi) || [];
  let pdf_link = null;
  let arxiv_link = null;

  linkTags.forEach(l => {
    const href = l.match(/href="([^"]+)"/)?.[1];
    const rel = l.match(/rel="([^"]+)"/)?.[1];
    const title = l.match(/title="([^"]+)"/)?.[1];

    if (title === 'pdf' && href) pdf_link = href;
    if (rel === 'alternate' && href) arxiv_link = href;
  });

  // Categories
  const categories = extractAllTags('category', entryXml)
    .map(c => c.match(/term="([^"]+)"/)?.[1])
    .filter(Boolean);

  return {
    json: {
      title: extractTag('title', entryXml),      
      summary: extractTag('summary', entryXml),
      arxiv_link      
    }
  };
});

return [
  {
    json: {
      papers,
      original_prompt: originalPrompt
    }
  }
];

